function showStudentPage(pageId){var _document$getElementB3;var addHistory=arguments.length>1&&arguments[1]!==undefined?arguments[1]:true;document.querySelectorAll('#dashboard-area .page').forEach(function(p){p.classList.remove('active');});var page=document.getElementById(pageId);if(page)page.classList.add('active');document.querySelectorAll('#student-sidebar .nav-item').forEach(function(n){n.classList.toggle('active',n.getAttribute('data-page')===pageId);});(_document$getElementB3=document.getElementById('student-sidebar'))===null||_document$getElementB3===void 0||_document$getElementB3.classList.remove('mobile-open');var bd2=document.getElementById('sidebar-backdrop');if(bd2)bd2.style.display='none';if(addHistory){history.pushState({page:pageId,area:'student'},'',"#".concat(pageId));}}// =============================================================
